{| class="wikitable"
! Article
| {{Update|type=article|demospace=main|date={{CURRENTMONTHNAME}} {{CURRENTYEAR}}}}
|-
! Category
| {{Update|type=category|demospace=category|date={{CURRENTMONTHNAME}} {{CURRENTYEAR}}}}
|-
! Template
| {{Update|type=template|demospace=template|date={{CURRENTMONTHNAME}} {{CURRENTYEAR}}}}
|}

{{tlx|Update|section}} produces:
{| class="wikitable"
! Article
| {{Update|section|type=article|demospace=main|date={{CURRENTMONTHNAME}} {{CURRENTYEAR}}}}
|-
! Category
| {{Update|section|type=category|demospace=category|date={{CURRENTMONTHNAME}} {{CURRENTYEAR}}}}
|-
! Template
| {{Update|section|type=template|demospace=template|date={{CURRENTMONTHNAME}} {{CURRENTYEAR}}}}
|}

This template will add [[WP:mainspace|mainspace]] articles to [[:Category:Wikipedia articles in need of updating]] (this category is not populated by pages in other [[WP:namespace|namespace]]s).

For factual inaccuracies, stronger wording is used and mainspace articles will be added to [[:Category:Articles with obsolete information]].

{{tlx|Update|2=inaccurate=yes}}
{{Update|type=article|demospace=main|inaccurate=yes}}

==TemplateData==
{{TemplateDataHeader}}
<templatedata>
{
	"description": "Use this tag to alert readers that the article may be biased by a conflict of interest.",
	"params": {
		"date": {
			"label": "Month and year",
			"description": "Provides the month and year of the citation request; e.g., 'January 2018', but not 'jan18'",
			"type": "string",
			"required": false,
			"autovalue": "{{subst:CURRENTMONTHNAME}} {{subst:CURRENTYEAR}}",
			"suggested": true
		},
		"updated": {
			"aliases": [
				"2"
			],
			"label": "Last updated",
			"description": "Date of last significant update",
			"type": "date"
		},
		"inaccurate": {
			"label": "Inaccurate?",
			"description": "Use 'yes' if the article has inaccuracies due to being out of date.",
			"example": "yes",
			"type": "boolean"
		},
		"talksection": {
			"aliases": [
				"discuss",
				"talk"
			],
			"label": "Talk page section",
			"description": "Section name on talk page where the discussion takes place",
			"type": "string"
		},
		"reason": {
			"label": "Reason",
			"description": "Explanation why the article is out of date",
			"type": "content"
		},
		"type": {
			"aliases": [
				"part",
				"1"
			],
			"label": "Type (section)",
			"description": "Part that needs updating (e.g. to replace the word \"article\", often \"section\")",
			"example": "section",
			"type": "string",
			"default": "article",
			"autovalue": ""
		}
	},
	"format": "inline",
	"paramOrder": [
		"type",
		"date",
		"updated",
		"inaccurate",
		"talksection",
		"reason"
	]
}
</templatedata>

